import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [mensagem, setMensagem] = useState('');
  const [periodos, setPeriodos] = useState([]);
  const [periodoId, setPeriodoId] = useState('');

  useEffect(() => {
    axios.get('/api/periodos').then(res => setPeriodos(res.data));
  }, []);

  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome);
      setRa(alunoEditando.ra);
      setPeriodoId(alunoEditando.periodo_id);
    } else {
      setNome('');
      setRa('');
      setPeriodoId('');
    }
  }, [alunoEditando]);

  // Validar nome e sobrenome
  function validarNomeCompleto(nome) {
    const partes = nome.trim().split(' ').filter(p => p.length >= 2);
    return partes.length >= 2;
  }

  function validarRA(ra) {
    return /^\d{1,9}$/.test(ra);
  }

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validarNomeCompleto(nome)) {
      setMensagem("Informe o nome completo!");
      return;
    }
    if (!validarRA(ra)) {
      setMensagem("O RA deve conter apenas números e até 9 dígitos!");
      return;
    }
    if (!periodoId) {
      setMensagem("Selecione um período!");
      return;
    }

    if (alunoEditando) {
      axios.put(`/api/alunos/${alunoEditando.id}`, { nome, ra, periodo_id: periodoId })
        .then(() => {
          setMensagem('Aluno atualizado!');
          setNome('');
          setRa('');
          setPeriodoId('');
          onNovoAluno();
          onFimEdicao();
        })
        .catch(() => setMensagem('Erro ao atualizar aluno.'));
    } else {
      axios.post('/api/alunos', { nome, ra, periodo_id: periodoId })
        .then(() => {
          setMensagem('Aluno cadastrado!');
          setNome('');
          setRa('');
          setPeriodoId('');
          onNovoAluno();
        })
        .catch(() => setMensagem('Erro ao cadastrar aluno.'));
    }
  };

  return (
    <div className="bg-white mx-auto max-w-lg rounded-2xl p-6 shadow-md">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
        </h2>
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome completo
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              value={nome}
              onChange={e => setNome(e.target.value)}
              required
              placeholder="Nome e sobrenome"
            />
          </label>
        </div>
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            RA
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              value={ra}
              onChange={e => setRa(e.target.value.replace(/\D/g, '').slice(0, 9))}
              maxLength={9}
              required
              placeholder="Somente números (até 9 dígitos)"
            />
          </label>
        </div>
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Período
            <select
              className="w-full border rounded px-3 py-2 mt-1"
              value={periodoId}
              onChange={e => setPeriodoId(e.target.value)}
              required
            >
              <option value="">Selecione um período</option>
              {periodos.map(periodo => (
                <option key={periodo.id} value={periodo.id}>
                  {periodo.nome}
                </option>
              ))}
            </select>
          </label>
        </div>
        <div className="flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#3172C0] hover:bg-[#083A76] text-white font-bold py-2 px-6 rounded-full"
          >
            {alunoEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {alunoEditando && (
            <button
              type="button"
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>
        {mensagem && <p className="mt-4 text-red-600">{mensagem}</p>}
      </form>
    </div>
  );
}

export default FormAluno;
